<script setup lang="ts">
import{Check,Edit3,Heart,Inbox,LoaderCircle,Send,X}from'@lucide/vue'
type Letter={id:string;senderId:string;recipientId:string;content:string;createdAt:string}
const{$supabase}=useNuxtApp();const{profile,demoMode}=useCoupleAuth();const{recordActivity}=useCouplePet();const{members,loadMembers}=useAccountManagement();const letters=ref<Letter[]>([]),view=ref<'received'|'sent'>('received'),editing=ref(false),loading=ref(true),busy=ref(false),draft=ref(''),error=ref('');let letterChannel:any=null
const partner=computed(()=>members.value.find(x=>x.id!==profile.value?.id));const received=computed(()=>letters.value.filter(x=>x.recipientId===profile.value?.id));const sent=computed(()=>letters.value.filter(x=>x.senderId===profile.value?.id));const visible=computed(()=>view.value==='received'?received.value:sent.value);const latest=computed(()=>visible.value[0]);function name(id:string){return members.value.find(x=>x.id===id)?.displayName||(id===profile.value?.id?'我':'TA')}function time(value:string){return new Intl.DateTimeFormat('zh-CN',{year:'numeric',month:'long',day:'numeric',hour:'2-digit',minute:'2-digit'}).format(new Date(value))}
function mapLetter(r:any):Letter{return{id:r.id,senderId:r.sender_id,recipientId:r.recipient_id,content:r.content,createdAt:r.created_at}}
async function subscribeLetters(){if(!$supabase||demoMode.value||letterChannel||!profile.value?.coupleId)return;letterChannel=$supabase.channel(`letters:${profile.value.coupleId}`).on('broadcast',{event:'letter'},({payload}:any)=>{const item=payload as Letter;if(!letters.value.some(x=>x.id===item.id))letters.value.unshift(item)}).on('postgres_changes',{event:'INSERT',schema:'public',table:'couple_letters',filter:`couple_id=eq.${profile.value.coupleId}`},(payload:any)=>{if(!letters.value.some(x=>x.id===payload.new.id))letters.value.unshift(mapLetter(payload.new))}).on('postgres_changes',{event:'DELETE',schema:'public',table:'couple_letters',filter:`couple_id=eq.${profile.value.coupleId}`},(payload:any)=>{letters.value=letters.value.filter(x=>x.id!==payload.old.id)}).subscribe()}
async function loadLetters(){loading.value=true;try{await loadMembers();if(!$supabase||demoMode.value){letters.value=JSON.parse(localStorage.getItem('couple-space-letters')||'[]');return}const{data,error:e}=await $supabase.from('couple_letters').select('*').order('created_at',{ascending:false});if(e)throw e;letters.value=(data||[]).map(mapLetter);await subscribeLetters()}catch(e:any){error.value=e.message}finally{loading.value=false}}onMounted(loadLetters);onBeforeUnmount(async()=>{if(letterChannel&&$supabase)await $supabase.removeChannel(letterChannel);letterChannel=null})
async function sendLetter(){if(!draft.value.trim()||!partner.value)return;busy.value=true;error.value='';try{let item={id:crypto.randomUUID(),senderId:profile.value!.id,recipientId:partner.value.id,content:draft.value.trim(),createdAt:new Date().toISOString()};if(!$supabase||demoMode.value){letters.value.unshift(item);localStorage.setItem('couple-space-letters',JSON.stringify(letters.value))}else{const{data,error:e}=await $supabase.from('couple_letters').insert({couple_id:profile.value!.coupleId,sender_id:profile.value!.id,recipient_id:partner.value.id,content:draft.value.trim()}).select('*').single();if(e)throw e;item=mapLetter(data);if(!letters.value.some(x=>x.id===item.id))letters.value.unshift(item);await letterChannel?.send({type:'broadcast',event:'letter',payload:item})}void recordActivity();draft.value='';editing.value=false;view.value='sent'}catch(e:any){error.value=e.message}finally{busy.value=false}}
</script>
<template><article class="love-letter panel"><header><div><p class="eyebrow">OUR PRIVATE MAILBOX</p><h3>只属于你们的情书</h3></div><button type="button" @click="editing=true"><Edit3 :size="16"/>写给 {{partner?.displayName||'TA'}}</button></header><nav><button :class="{active:view==='received'}" @click="view='received'"><Inbox :size="15"/>TA 写给我 <span>{{received.length}}</span></button><button :class="{active:view==='sent'}" @click="view='sent'"><Send :size="15"/>我写给 TA <span>{{sent.length}}</span></button></nav><div v-if="loading" class="state"><LoaderCircle class="spin"/>正在打开信箱</div><div v-else-if="visible.length" class="letter-list"><article v-for="letter in visible" :key="letter.id"><div class="seal"><Heart fill="currentColor" :size="18"/></div><div><small>{{name(letter.senderId)}} 写给 {{name(letter.recipientId)}} · {{time(letter.createdAt)}}</small><p>{{letter.content}}</p><footer>署名：{{name(letter.senderId)}}</footer></div></article></div><div v-else class="state empty"><Heart :size="27"/><b>{{view==='received'?'还没有收到 TA 的信':'你还没有写信给 TA'}}</b><span>{{view==='received'?'等 TA 写下第一封信，它会出现在这里。':'有些真心，值得认真写下来。'}}</span></div><p v-if="error" class="error">{{error}}</p><Teleport to="body"><div v-if="editing" class="editor-overlay" @click.self="editing=false"><section class="editor"><aside><Heart :size="34" fill="currentColor"/><span>TO {{partner?.displayName||'TA'}}</span><h3>这封信会只出现在 TA 的“写给我的信”里。</h3><p>保存后不会覆盖以前的信，每一封都会保留你的署名和发送时间。</p></aside><main><header><div><small>FROM {{profile?.displayName||'我'}}</small><h2>写给 {{partner?.displayName||'TA'}}</h2></div><button type="button" aria-label="关闭" @click="editing=false"><X/></button></header><textarea v-model="draft" maxlength="1200" placeholder="亲爱的……&#10;&#10;我一直想告诉你……"/><footer><span>{{draft.length}} / 1200</span><div><button @click="editing=false">取消</button><button class="send" :disabled="busy||!draft.trim()||!partner" @click="sendLetter"><LoaderCircle v-if="busy" class="spin"/><Send v-else/>署名并寄给 TA</button></div></footer></main></section></div></Teleport></article></template>
<style scoped>
.love-letter{grid-column:1/-1;min-height:300px;background:linear-gradient(135deg,rgba(255,251,255,.94),rgba(251,230,244,.9))}.love-letter>header{display:flex;justify-content:space-between}.love-letter>header h3{margin:0;font-size:18px}.love-letter>header button{display:flex;align-items:center;gap:6px;height:39px;padding:0 14px;border:0;border-radius:17px;background:#eedbf3;color:#784787;font-size:10px;font-weight:800}.love-letter>nav{display:flex;gap:6px;margin-top:18px}.love-letter>nav button{display:flex;align-items:center;gap:6px;padding:9px 12px;border:0;border-radius:14px;background:transparent;color:#8d788f;font-size:10px}.love-letter>nav button.active{background:#fff;color:#784787;box-shadow:0 7px 18px rgba(89,54,99,.08)}.love-letter>nav span{display:grid;place-items:center;min-width:18px;height:18px;border-radius:9px;background:#ead9ef;font-size:8px}.letter-list{display:grid;gap:9px;max-height:310px;margin-top:15px;overflow:auto}.letter-list>article{display:grid;grid-template-columns:auto 1fr;gap:13px;padding:18px;border-radius:20px;background:rgba(255,255,255,.78)}.seal{display:grid;place-items:center;width:39px;height:39px;border-radius:50%;background:#f1d8e7;color:#c75c91}.letter-list small{color:#a16b9d;font-size:9px;font-weight:750}.letter-list p{margin:8px 0;color:#58455c;font-size:13px;line-height:1.8;white-space:pre-wrap}.letter-list footer{color:#9d879f;font-size:9px}.state{display:flex;min-height:170px;align-items:center;justify-content:center;flex-direction:column;gap:8px;color:#967f99;text-align:center}.state b{color:#5e4863}.state span{font-size:9px}.error{color:#b84f74;font-size:10px}.editor-overlay{position:fixed;z-index:95;inset:0;display:grid;place-items:center;padding:20px;background:rgba(48,34,53,.34);backdrop-filter:blur(13px)}.editor{display:grid;grid-template-columns:250px 1fr;width:min(100%,850px);height:min(680px,calc(100dvh - 40px));overflow:hidden;border-radius:30px;background:#fffafd;box-shadow:0 35px 90px rgba(54,35,60,.24)}.editor aside{display:flex;flex-direction:column;justify-content:center;padding:35px;background:linear-gradient(155deg,#e3c7f5,#f7d1e2);color:#603d68}.editor aside span{margin-top:20px;font-size:9px;font-weight:850}.editor aside h3{font-size:22px;line-height:1.5}.editor aside p{font-size:10px;line-height:1.8}.editor main{display:grid;grid-template-rows:auto minmax(0,1fr) auto;padding:30px}.editor main header,.editor main footer{display:flex;justify-content:space-between;align-items:center}.editor h2{margin:5px 0}.editor header small{color:#ad75aa;font-size:9px}.editor header button{display:grid;place-items:center;width:38px;height:38px;border:0;border-radius:14px;background:#f0e5f2}.editor textarea{width:100%;height:100%;margin:20px 0 13px;padding:21px;border:1px solid #eadceb;border-radius:19px;outline:0;resize:none;background:repeating-linear-gradient(#fff 0,#fff 31px,#f0e8f1 32px);font:inherit;font-size:14px;line-height:32px}.editor footer>span{color:#a58ba8;font-size:9px}.editor footer>div{display:flex;gap:8px}.editor footer button{min-height:43px;padding:0 16px;border:0;border-radius:17px;background:#f0e6f2}.editor footer .send{display:flex;align-items:center;gap:7px;background:linear-gradient(135deg,#8b4db9,#d85f99);color:#fff;font-weight:800}.spin{animation:spin 1s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}@media(max-width:700px){.love-letter{grid-column:auto}.love-letter>header{gap:12px}.editor-overlay{align-items:end;padding:0}.editor{grid-template-columns:1fr;width:100%;height:88dvh;border-radius:25px 25px 0 0}.editor aside{display:none}.editor main{padding:21px 15px calc(18px + env(safe-area-inset-bottom))}}
</style>
<style scoped>
@media(max-width:650px){.editor-overlay{padding-top:env(safe-area-inset-top)}.editor{height:calc(100dvh - env(safe-area-inset-top));max-height:88dvh}.editor h2{font-size:21px}.letter-list p{font-size:12px}.love-letter>header h3{font-size:15px}}
</style>
